from flask import Flask, request, jsonify
import random
import string

app = Flask(__name__)

users = {
    "user1@example.com": {
        "password": "password123",
        "mfa_enabled": True,
        "reset_token": None
    },
    "user2@example.com": {
        "password": "securepass",
        "mfa_enabled": False,
        "reset_token": None
    }
}

def generate_reset_token():
    return ''.join(random.choices(string.ascii_letters + string.digits, k=20))

@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    email = request.json.get('email')
    if email in users:
        reset_token = generate_reset_token()
        users[email]['reset_token'] = reset_token
        # Send reset link to the user's email (implementation not included)
        return jsonify({"message": "Reset link sent to email"})
    else:
        return jsonify({"error": "User not found"})

@app.route('/disable-mfa', methods=['POST'])
def disable_mfa():
    email = request.json.get('email')
    password = request.json.get('password')
    if email in users and users[email]['password'] == password:
        users[email]['mfa_enabled'] = False
        return jsonify({"message": "MFA disabled successfully"})
    else:
        return jsonify({"error": "Invalid email or password"})

if __name__ == '__main__':
    app.run(debug=True)